#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,a=0,b=0,c[1000050],x,p=0;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>x;
        c[x]++;
        if(x%2==0){
            a++;
        }
        else{
            b++;
        }
    }
    if(a<b){
		p=-1;
	}
    for(int i=0;i<500050;i++){
        p+=2;
        if(c[p]!=1){
            cout<<p;
            return 0;
        }
    }
    return 0;
}
